// ============================================================
// THEME
// ============================================================
document.addEventListener('DOMContentLoaded', () => {

    // Mobile nav
    const navToggle = document.getElementById('navToggle');
    const navMobile = document.getElementById('navMobile');
    navToggle?.addEventListener('click', () => {
        const open = navMobile.classList.toggle('open');
        navToggle.setAttribute('aria-expanded', open);
    });
    navMobile?.querySelectorAll('a').forEach(a => {
        a.addEventListener('click', () => navMobile.classList.remove('open'));
    });

    // Back to top
    const btt = document.getElementById('backToTop');
    window.addEventListener('scroll', () => {
        if (window.scrollY > 600) { btt.hidden = false; btt.classList.add('show'); }
        else { btt.classList.remove('show'); setTimeout(() => btt.hidden = true, 200); }
    }, { passive: true });
    btt.addEventListener('click', () => window.scrollTo({ top: 0, behavior: 'smooth' }));

    if (!RAW || !RAW.reviews || !RAW.reviews.length) {
        document.getElementById('summaryCards').innerHTML =
            '<div class="s-card warn" style="grid-column:1/-1"><div class="num" style="font-size:18px">⚠ No data</div><div class="lbl">Paste your reviews into RAW.reviews in script.js</div></div>';
        return;
    }

    const reviews = RAW.reviews;
    const total = reviews.length;

    // ============================================================
    // FORMATTERS
    // ============================================================
    const fmtMoney = (n) => {
        if (n >= 1e6) return '$' + (n / 1e6).toFixed(1) + 'M';
        if (n >= 1e3) return '$' + (n / 1e3).toFixed(0) + 'K';
        return '$' + Math.round(n);
    };
    const fmtNum = (n) => n.toLocaleString('en-US', { maximumFractionDigits: 0 });
    const fmtDate = (ts) => new Date(ts * 1000).toLocaleDateString('en-US', { day: 'numeric', month: 'short', year: 'numeric' });
    const fmtDateShort = (ts) => new Date(ts * 1000).toLocaleDateString('en-US', { month: 'short', year: 'numeric' });

    // ============================================================
    // METRICS (computed once, memoized)
    // ============================================================
    const metrics = (() => {
        const totalRevenue = reviews.reduce((s, r) => s + (r.price_usd || 0), 0);
        const avgRating = reviews.reduce((s, r) => s + (r.rating || 0), 0) / total;
        const uniqueClients = new Set(reviews.map(r => r.from_user_id)).size;
        const completeCount = reviews.filter(r => r.review_project_status === 'complete').length;
        const fiveStar = reviews.filter(r => r.rating >= 4.95).length;
        const negCount = reviews.filter(r => r.rating > 0 && r.rating <= 2.0).length;

        const clientMap = {};
        reviews.forEach(r => {
            const cid = r.from_user_id;
            if (!clientMap[cid]) clientMap[cid] = { id: cid, reviews: [], totalUsd: 0, ratings: [] };
            clientMap[cid].reviews.push(r);
            clientMap[cid].totalUsd += r.price_usd || 0;
            if (r.rating > 0) clientMap[cid].ratings.push(r.rating);
        });
        const repeatClients = Object.values(clientMap).filter(c => c.reviews.length >= 3).sort((a, b) => b.totalUsd - a.totalUsd);

        let onTimeYes = 0, onTimeNo = 0, onBudgetYes = 0, onBudgetNo = 0;
        reviews.forEach(r => {
            const d = r.rating_details; if (!d) return;
            const ot = d.on_time_display, ob = d.on_budget_display;
            if (ot === 'YES' || ot === '100%') onTimeYes++; else if (ot === 'NO') onTimeNo++;
            if (ob === 'YES' || ob === '100%') onBudgetYes++; else if (ob === 'NO') onBudgetNo++;
        });

        const dates = reviews.map(r => r.time_submitted).sort();
        const earliest = new Date(dates[0] * 1000);
        const latest = new Date(dates[dates.length - 1] * 1000);

        return {
            totalRevenue, avgRating, uniqueClients, completeCount, fiveStar, negCount,
            clientMap, repeatClients, onTimeYes, onTimeNo, onBudgetYes, onBudgetNo,
            earliest, latest
        };
    })();

    // ============================================================
    // SUMMARY CARDS — with count-up animation
    // ============================================================
    const cards = [
        { num: total, lbl: 'Total Reviews', sub: `${metrics.earliest.getFullYear()} – ${metrics.latest.getFullYear()}`, type: 'int' },
        { num: metrics.totalRevenue, lbl: 'Total Revenue', sub: 'All currencies → USD', type: 'money' },
        { num: metrics.avgRating, lbl: 'Avg Rating', sub: `${metrics.fiveStar} five-star`, cls: 'good', type: 'decimal' },
        { num: metrics.uniqueClients, lbl: 'Unique Clients', sub: `${metrics.repeatClients.length} repeat (3+)`, type: 'int' },
        { num: metrics.completeCount, lbl: 'Completed', sub: `${total - metrics.completeCount} incomplete`, type: 'int' },
        { num: metrics.negCount, lbl: 'Negative (≤2.0)', sub: `${(metrics.negCount / total * 100).toFixed(1)}% of total`, cls: 'warn', type: 'int' },
        { num: Math.round(metrics.onTimeYes / (metrics.onTimeYes + metrics.onTimeNo) * 100), lbl: 'On Time', sub: `${metrics.onTimeYes} yes / ${metrics.onTimeNo} no`, cls: 'good', type: 'percent' },
        { num: Math.round(metrics.onBudgetYes / (metrics.onBudgetYes + metrics.onBudgetNo) * 100), lbl: 'On Budget', sub: `${metrics.onBudgetYes} yes / ${metrics.onBudgetNo} no`, cls: 'good', type: 'percent' },
    ];

    const formatCard = (val, type) => {
        if (type === 'money') return fmtMoney(val);
        if (type === 'decimal') return val.toFixed(2);
        if (type === 'percent') return val + '%';
        return fmtNum(val);
    };

    document.getElementById('summaryCards').innerHTML = cards.map((c, i) =>
        `<div class="s-card ${c.cls || ''}" style="animation-delay:${i * 50}ms">
      <div class="num" data-target="${c.num}" data-type="${c.type}">${formatCard(0, c.type)}</div>
      <div class="lbl">${c.lbl}</div>
      ${c.sub ? `<div class="sub">${c.sub}</div>` : ''}
    </div>`
    ).join('');

    // Count-up animation
    const animateCount = (el) => {
        const target = parseFloat(el.dataset.target);
        const type = el.dataset.type;
        const duration = 1200;
        const start = performance.now();
        const step = (now) => {
            const p = Math.min((now - start) / duration, 1);
            const eased = 1 - Math.pow(1 - p, 3);
            el.textContent = formatCard(target * eased, type);
            if (p < 1) requestAnimationFrame(step);
            else el.textContent = formatCard(target, type);
        };
        requestAnimationFrame(step);
    };

    const countObs = new IntersectionObserver((entries) => {
        entries.forEach(e => {
            if (e.isIntersecting) { animateCount(e.target); countObs.unobserve(e.target); }
        });
    }, { threshold: 0.5 });
    document.querySelectorAll('.s-card .num').forEach(el => countObs.observe(el));

    // ============================================================
    // CHARTS — lazy render via IntersectionObserver
    // ============================================================
    const charts = {};
    const PALETTE = ['#CC785C', '#E8B4A0', '#5C7A4F', '#B85C3E', '#C9A24C', '#6B6B66',
        '#3D3D3A', '#8B6F5F', '#7A9B6B', '#D4A24C', '#9B7A5C', '#5C6B7A'];

    const renderCharts = () => {
        if (typeof Chart === 'undefined') { setTimeout(renderCharts, 100); return; }

        Chart.defaults.color = '#6B6B66';
        Chart.defaults.borderColor = '#E5E2D6';
        Chart.defaults.font.family = "'Inter', sans-serif";

        const baseOpts = {
            responsive: true,
            maintainAspectRatio: false,
            plugins: { legend: { display: false } },
            animation: { duration: 800, easing: 'easeOutQuart' }
        };

        // Rating distribution
        const ratingBuckets = { '5.0': 0, '4.0–4.9': 0, '3.0–3.9': 0, '2.0–2.9': 0, '1.0–1.9': 0, '0 (Dispute)': 0 };
        reviews.forEach(r => {
            if (r.rating >= 4.95) ratingBuckets['5.0']++;
            else if (r.rating >= 4.0) ratingBuckets['4.0–4.9']++;
            else if (r.rating >= 3.0) ratingBuckets['3.0–3.9']++;
            else if (r.rating >= 2.0) ratingBuckets['2.0–2.9']++;
            else if (r.rating >= 0.1) ratingBuckets['1.0–1.9']++;
            else ratingBuckets['0 (Dispute)']++;
        });
        charts.rating = new Chart(document.getElementById('chartRating'), {
            type: 'bar',
            data: { labels: Object.keys(ratingBuckets), datasets: [{ data: Object.values(ratingBuckets), backgroundColor: ['#5C7A4F', '#8B9B6B', '#C9A24C', '#E8B4A0', '#CC785C', '#B85C3E'], borderRadius: 6 }] },
            options: { ...baseOpts, scales: { y: { beginAtZero: true, grid: { color: '#E5E2D6' } }, x: { grid: { display: false } } } }
        });

        // Revenue by year
        const yearRev = {};
        reviews.forEach(r => {
            const y = new Date(r.time_submitted * 1000).getFullYear();
            yearRev[y] = (yearRev[y] || 0) + (r.price_usd || 0);
        });
        const yearKeys = Object.keys(yearRev).sort();
        charts.revenue = new Chart(document.getElementById('chartRevenue'), {
            type: 'bar',
            data: { labels: yearKeys, datasets: [{ data: yearKeys.map(y => Math.round(yearRev[y])), backgroundColor: '#CC785C', borderRadius: 6 }] },
            options: { ...baseOpts, scales: { y: { beginAtZero: true, grid: { color: '#E5E2D6' }, ticks: { callback: v => fmtMoney(v) } }, x: { grid: { display: false } } } }
        });

        // Categories
        const catMap = {};
        reviews.forEach(r => {
            const url = r.review_context?.seo_url || '';
            const parts = url.split('/');
            const cat = parts.length >= 2 ? parts[1] : 'other';
            catMap[cat] = (catMap[cat] || 0) + 1;
        });
        const catSorted = Object.entries(catMap).sort((a, b) => b[1] - a[1]).slice(0, 12);
        charts.categories = new Chart(document.getElementById('chartCategories'), {
            type: 'doughnut',
            data: { labels: catSorted.map(c => c[0]), datasets: [{ data: catSorted.map(c => c[1]), backgroundColor: PALETTE, borderWidth: 2, borderColor: '#FAF9F5' }] },
            options: { responsive: true, maintainAspectRatio: false, cutout: '60%', plugins: { legend: { position: 'right', labels: { font: { size: 11 }, padding: 8, boxWidth: 10 } } } }
        });

        // Delivery
        charts.delivery = new Chart(document.getElementById('chartDelivery'), {
            type: 'bar',
            data: {
                labels: ['On Time', 'Late', 'On Budget', 'Over Budget'],
                datasets: [{ data: [metrics.onTimeYes, metrics.onTimeNo, metrics.onBudgetYes, metrics.onBudgetNo], backgroundColor: ['#5C7A4F', '#B85C3E', '#5C7A4F', '#B85C3E'], borderRadius: 6 }]
            },
            options: { ...baseOpts, scales: { y: { beginAtZero: true, grid: { color: '#E5E2D6' } }, x: { grid: { display: false } } } }
        });

        // Category ratings
        const catRatingSums = { professionalism: 0, communication: 0, quality: 0, expertise: 0, hire_again: 0 };
        const catRatingCounts = { ...catRatingSums };
        reviews.forEach(r => {
            const cr = r.rating_details?.category_ratings; if (!cr) return;
            Object.keys(catRatingSums).forEach(k => {
                if (cr[k] != null) { catRatingSums[k] += cr[k]; catRatingCounts[k]++; }
            });
        });
        const catRatingAvgs = Object.keys(catRatingSums).map(k => catRatingCounts[k] ? +(catRatingSums[k] / catRatingCounts[k]).toFixed(2) : 0);
        charts.catRatings = new Chart(document.getElementById('chartCatRatings'), {
            type: 'radar',
            data: {
                labels: ['Professionalism', 'Communication', 'Quality', 'Expertise', 'Hire Again'],
                datasets: [{ data: catRatingAvgs, backgroundColor: 'rgba(204, 120, 92, 0.15)', borderColor: '#CC785C', pointBackgroundColor: '#CC785C', borderWidth: 2, pointRadius: 4 }]
            },
            options: { responsive: true, maintainAspectRatio: false, scales: { r: { min: 0, max: 5, ticks: { stepSize: 1, color: '#6B6B66', backdropColor: 'transparent' }, grid: { color: '#E5E2D6' }, angleLines: { color: '#E5E2D6' }, pointLabels: { color: '#1F1E1D', font: { size: 11 } } } }, plugins: { legend: { display: false } } }
        });

        // Currency
        const currMap = {};
        reviews.forEach(r => { const cc = r.currency?.code || 'USD'; currMap[cc] = (currMap[cc] || 0) + 1; });
        const currSorted = Object.entries(currMap).sort((a, b) => b[1] - a[1]);
        charts.currency = new Chart(document.getElementById('chartCurrency'), {
            type: 'doughnut',
            data: { labels: currSorted.map(c => c[0]), datasets: [{ data: currSorted.map(c => c[1]), backgroundColor: PALETTE, borderWidth: 2, borderColor: '#FAF9F5' }] },
            options: { responsive: true, maintainAspectRatio: false, cutout: '60%', plugins: { legend: { position: 'right', labels: { font: { size: 11 }, padding: 8, boxWidth: 10 } } } }
        });
    };

    // Lazy-render charts when scrolled into view
    const chartsSection = document.getElementById('charts');
    const chartObs = new IntersectionObserver((entries, obs) => {
        if (entries[0].isIntersecting) { renderCharts(); obs.disconnect(); }
    }, { rootMargin: '200px' });
    chartObs.observe(chartsSection);

    // ============================================================
    // CLIENT TABLE
    // ============================================================
    let clientSortKey = 'spend', clientSortDir = -1;

    const renderClients = () => {
        const sorted = [...metrics.repeatClients].sort((a, b) => {
            if (clientSortKey === 'name') return clientSortDir * (a.id - b.id);
            if (clientSortKey === 'count') return clientSortDir * (a.reviews.length - b.reviews.length);
            if (clientSortKey === 'spend') return clientSortDir * (a.totalUsd - b.totalUsd);
            if (clientSortKey === 'avg') {
                const aa = a.ratings.length ? a.ratings.reduce((s, v) => s + v, 0) / a.ratings.length : 0;
                const bb = b.ratings.length ? b.ratings.reduce((s, v) => s + v, 0) / b.ratings.length : 0;
                return clientSortDir * (aa - bb);
            }
            if (clientSortKey === 'first') return clientSortDir * (Math.min(...a.reviews.map(r => r.time_submitted)) - Math.min(...b.reviews.map(r => r.time_submitted)));
            if (clientSortKey === 'last') return clientSortDir * (Math.max(...a.reviews.map(r => r.time_submitted)) - Math.max(...b.reviews.map(r => r.time_submitted)));
            return 0;
        });

        document.getElementById('clientBody').innerHTML = sorted.map(c => {
            const avg = c.ratings.length ? (c.ratings.reduce((s, v) => s + v, 0) / c.ratings.length).toFixed(2) : '—';
            const first = Math.min(...c.reviews.map(r => r.time_submitted));
            const last = Math.max(...c.reviews.map(r => r.time_submitted));
            const projects = c.reviews.map(r => r.review_context?.context_name || '').filter(Boolean).slice(0, 3).join(', ');
            const avgColor = parseFloat(avg) >= 4.5 ? 'var(--good)' : parseFloat(avg) >= 3 ? 'var(--gold)' : 'var(--warn)';
            return `<tr>
        <td><div class="tbl-name">#${c.id}</div><div class="tbl-sub">${projects.substring(0, 60)}${projects.length > 60 ? '…' : ''}</div></td>
        <td><strong>${c.reviews.length}</strong></td>
        <td><strong>$${fmtNum(c.totalUsd)}</strong></td>
        <td><span style="color:${avgColor};font-weight:600">${avg}</span></td>
        <td>${fmtDateShort(first)}</td>
        <td>${fmtDateShort(last)}</td>
      </tr>`;
        }).join('');

        // Update sort indicators
        document.querySelectorAll('#clientTable th').forEach(t => {
            const icon = t.querySelector('.sort-icon');
            if (t.dataset.sort === clientSortKey) {
                t.classList.add('active');
                if (icon) icon.textContent = clientSortDir === -1 ? '↓' : '↑';
            } else {
                t.classList.remove('active');
                if (icon) icon.textContent = '↕';
            }
        });
    };

    document.querySelectorAll('#clientTable th').forEach(th => {
        th.addEventListener('click', () => {
            const key = th.dataset.sort;
            if (clientSortKey === key) clientSortDir *= -1;
            else { clientSortKey = key; clientSortDir = -1; }
            renderClients();
        });
    });

    renderClients();

    // CSV Export
    document.getElementById('exportCSV').addEventListener('click', () => {
        const rows = [['Client ID', 'Projects', 'Total Spend USD', 'Avg Rating', 'First Review', 'Last Review']];
        metrics.repeatClients.forEach(c => {
            const avg = c.ratings.length ? (c.ratings.reduce((s, v) => s + v, 0) / c.ratings.length).toFixed(2) : '';
            const first = fmtDate(Math.min(...c.reviews.map(r => r.time_submitted)));
            const last = fmtDate(Math.max(...c.reviews.map(r => r.time_submitted)));
            rows.push([c.id, c.reviews.length, c.totalUsd.toFixed(2), avg, first, last]);
        });
        const csv = rows.map(r => r.map(v => `"${String(v).replace(/"/g, '""')}"`).join(',')).join('\n');
        const blob = new Blob([csv], { type: 'text/csv' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url; a.download = 'narola-repeat-clients.csv'; a.click();
        URL.revokeObjectURL(url);
    });

    // ============================================================
    // INSIGHTS
    // ============================================================
    const biggestProjects = [...reviews].sort((a, b) => (b.price_usd || 0) - (a.price_usd || 0)).slice(0, 5);
    const negReviews = reviews.filter(r => r.rating > 0 && r.rating <= 2.0).sort((a, b) => a.rating - b.rating);

    const descMap = {};
    reviews.forEach(r => {
        const d = (r.description || '').trim().substring(0, 80);
        if (d.length > 20) descMap[d] = (descMap[d] || 0) + 1;
    });
    const dupeDescs = Object.entries(descMap).filter(d => d[1] >= 3).sort((a, b) => b[1] - a[1]).slice(0, 5);

    const bids = reviews.filter(r => r.bid_amount > 0 && r.paid_amount > 0);
    const avgBid = bids.reduce((s, r) => s + r.bid_amount, 0) / bids.length;
    const avgPaid = bids.reduce((s, r) => s + r.paid_amount, 0) / bids.length;
    const sortedPaid = reviews.map(r => r.price_usd || 0).sort((a, b) => a - b);
    const medianPaid = sortedPaid[Math.floor(total / 2)];

    document.getElementById('insightGrid').innerHTML = `
    <div class="insight">
      <h4><i class="fa-solid fa-trophy"></i> Biggest Projects (by USD)</h4>
      ${biggestProjects.map(r => `<div class="insight-row"><span class="insight-key">${(r.review_context?.context_name || '').substring(0, 40)}</span><span class="insight-val">$${fmtNum(r.price_usd || 0)}</span></div>`).join('')}
    </div>
    <div class="insight">
      <h4><i class="fa-solid fa-triangle-exclamation"></i> Negative Reviews (≤2.0)</h4>
      ${negReviews.length === 0 ? '<div class="insight-row"><span class="insight-key">None found 🎉</span></div>' :
            negReviews.slice(0, 6).map(r => `<div class="insight-row"><span class="insight-key">${(r.review_context?.context_name || '').substring(0, 35)}</span><span class="insight-val" style="color:var(--warn)">${r.rating.toFixed(1)} ★</span></div>`).join('')}
    </div>
    <div class="insight">
      <h4><i class="fa-solid fa-coins"></i> Bid vs Actual Payment</h4>
      <div class="insight-row"><span class="insight-key">Avg Bid Amount</span><span class="insight-val">$${avgBid.toFixed(0)}</span></div>
      <div class="insight-row"><span class="insight-key">Avg Paid Amount</span><span class="insight-val">$${avgPaid.toFixed(0)}</span></div>
      <div class="insight-row"><span class="insight-key">Avg Multiplier</span><span class="insight-val">${(avgPaid / avgBid).toFixed(1)}x</span></div>
      <div class="insight-row"><span class="insight-key">Median Paid (USD)</span><span class="insight-val">$${medianPaid.toFixed(0)}</span></div>
    </div>
    <div class="insight">
      <h4><i class="fa-solid fa-copy"></i> Duplicate Review Texts</h4>
      ${dupeDescs.length === 0 ? '<div class="insight-row"><span class="insight-key">No significant duplicates</span></div>' :
            dupeDescs.map(d => `<div class="insight-row"><span class="insight-key">"${d[0].substring(0, 45)}…"</span><span class="insight-val">${d[1]}x</span></div>`).join('')}
    </div>
    <div class="insight">
      <h4><i class="fa-solid fa-users"></i> Client Retention</h4>
      <div class="insight-row"><span class="insight-key">1-time clients</span><span class="insight-val">${Object.values(metrics.clientMap).filter(c => c.reviews.length === 1).length}</span></div>
      <div class="insight-row"><span class="insight-key">2-time clients</span><span class="insight-val">${Object.values(metrics.clientMap).filter(c => c.reviews.length === 2).length}</span></div>
      <div class="insight-row"><span class="insight-key">3-5 projects</span><span class="insight-val">${Object.values(metrics.clientMap).filter(c => c.reviews.length >= 3 && c.reviews.length <= 5).length}</span></div>
      <div class="insight-row"><span class="insight-key">6-10 projects</span><span class="insight-val">${Object.values(metrics.clientMap).filter(c => c.reviews.length >= 6 && c.reviews.length <= 10).length}</span></div>
      <div class="insight-row"><span class="insight-key">10+ projects</span><span class="insight-val">${Object.values(metrics.clientMap).filter(c => c.reviews.length > 10).length}</span></div>
    </div>
    <div class="insight">
      <h4><i class="fa-solid fa-handshake"></i> Longest Client Relationships</h4>
      ${Object.values(metrics.clientMap).filter(c => c.reviews.length >= 3).map(c => {
                const ts = c.reviews.map(r => r.time_submitted);
                return { id: c.id, span: (Math.max(...ts) - Math.min(...ts)) / (86400 * 365), count: c.reviews.length };
            }).sort((a, b) => b.span - a.span).slice(0, 5).map(c =>
                `<div class="insight-row"><span class="insight-key">#${c.id} (${c.count} proj)</span><span class="insight-val">${c.span.toFixed(1)} years</span></div>`
            ).join('')}
    </div>
  `;

    // ============================================================
    // ALL REVIEWS — search, filter, paginate
    // ============================================================
    const PER_PAGE = 15;
    let filtered = [...reviews];
    let page = 0;

    // Debounce helper
    const debounce = (fn, ms) => {
        let t; return (...args) => { clearTimeout(t); t = setTimeout(() => fn(...args), ms); };
    };

    const applyFilters = () => {
        const q = document.getElementById('rvSearch').value.toLowerCase().trim();
        const ratingFilter = document.getElementById('rvRating').value;
        const statusFilter = document.getElementById('rvStatus').value;
        const sortVal = document.getElementById('rvSort').value;

        document.getElementById('searchClear').hidden = q === '';

        filtered = reviews.filter(r => {
            if (q && !(r.review_context?.context_name || '').toLowerCase().includes(q) && !(r.description || '').toLowerCase().includes(q)) return false;
            if (statusFilter !== 'all' && r.review_project_status !== statusFilter) return false;
            if (ratingFilter !== 'all') {
                const rf = parseInt(ratingFilter);
                if (rf === 5 && r.rating < 4.95) return false;
                if (rf === 4 && (r.rating < 4.0 || r.rating >= 4.95)) return false;
                if (rf === 3 && (r.rating < 3.0 || r.rating >= 4.0)) return false;
                if (rf === 2 && (r.rating < 2.0 || r.rating >= 3.0)) return false;
                if (rf === 1 && r.rating >= 2.0) return false;
            }
            return true;
        });

        const sorters = {
            'date-desc': (a, b) => b.time_submitted - a.time_submitted,
            'date-asc': (a, b) => a.time_submitted - b.time_submitted,
            'rating-desc': (a, b) => b.rating - a.rating,
            'rating-asc': (a, b) => a.rating - b.rating,
            'amount-desc': (a, b) => (b.price_usd || 0) - (a.price_usd || 0),
            'amount-asc': (a, b) => (a.price_usd || 0) - (b.price_usd || 0)
        };
        if (sorters[sortVal]) filtered.sort(sorters[sortVal]);

        page = 0;
        renderReviews();
    };

    const renderReviews = () => {
        const start = page * PER_PAGE;
        const slice = filtered.slice(start, start + PER_PAGE);
        const totalPages = Math.max(1, Math.ceil(filtered.length / PER_PAGE));

        document.getElementById('rvMeta').textContent =
            filtered.length === 0 ? '0 reviews' : `${filtered.length} reviews · Page ${page + 1} of ${totalPages}`;

        if (filtered.length === 0) {
            document.getElementById('rvList').innerHTML = `
        <div class="rv-empty">
          <i class="fa-solid fa-magnifying-glass"></i>
          <h4>No reviews match your filters</h4>
          <p>Try adjusting your search or clearing filters.</p>
        </div>`;
            document.getElementById('rvPagination').innerHTML = '';
            return;
        }

        document.getElementById('rvList').innerHTML = slice.map(r => {
            const name = r.review_context?.context_name || 'Unnamed Project';
            const fullDesc = (r.description || '').split('\n')[0];
            const desc = fullDesc.substring(0, 240);
            const rClass = r.rating >= 4.0 ? 'pos' : r.rating <= 2.5 && r.rating > 0 ? 'neg' : '';
            const rColor = r.rating >= 4.5 ? 'high' : r.rating <= 2.5 && r.rating > 0 ? 'low' : '';
            const onTime = r.rating_details?.on_time_display || '—';
            const onBudget = r.rating_details?.on_budget_display || '—';
            const otClass = (onTime === 'YES' || onTime === '100%') ? 'good' : onTime === 'NO' ? 'warn' : '';
            const obClass = (onBudget === 'YES' || onBudget === '100%') ? 'good' : onBudget === 'NO' ? 'warn' : '';

            return `<div class="rv ${rClass}" data-id="${r.id}">
        <div class="rv-head">
          <div class="rv-proj">${name}</div>
          <div class="rv-rating ${rColor}">${r.rating > 0 ? r.rating.toFixed(1) : '⚠'}</div>
        </div>
        <div class="rv-meta">
          <span class="tag"><i class="fa-solid fa-calendar"></i>${fmtDate(r.time_submitted)}</span>
          <span class="tag"><i class="fa-solid fa-dollar-sign"></i>${r.currency?.sign || '$'}${fmtNum(r.paid_amount || 0)} ${r.currency?.code || 'USD'}</span>
          ${r.price_usd > 0 && r.currency?.code !== 'USD' ? `<span class="tag"><i class="fa-solid fa-right-left"></i>$${fmtNum(r.price_usd)} USD</span>` : ''}
          <span class="tag ${otClass}"><i class="fa-solid fa-clock"></i>On-time: ${onTime}</span>
          <span class="tag ${obClass}"><i class="fa-solid fa-wallet"></i>On-budget: ${onBudget}</span>
          <span class="tag"><i class="fa-solid fa-${r.review_project_status === 'complete' ? 'check' : 'xmark'}"></i>${r.review_project_status}</span>
          ${r.featured ? '<span class="tag" style="color:var(--gold);border-color:rgba(201,162,76,0.3)"><i class="fa-solid fa-star" style="color:var(--gold)"></i>Featured</span>' : ''}
        </div>
        <div class="rv-text">${desc}${fullDesc.length > 240 ? '…' : ''}</div>
        <div class="rv-foot">
          <span>Client #${r.from_user_id} · Project #${r.project_id}</span>
        </div>
      </div>`;
        }).join('');

        // Click to expand
        document.querySelectorAll('.rv').forEach(el => {
            el.addEventListener('click', () => {
                el.querySelector('.rv-text')?.classList.toggle('expanded');
            });
        });

        // Pagination
        const pag = document.getElementById('rvPagination');
        if (totalPages <= 1) { pag.innerHTML = ''; return; }
        let btns = `<button ${page === 0 ? 'disabled' : ''} data-go="${page - 1}">← Prev</button>`;
        const maxBtns = 7;
        let startP = Math.max(0, page - Math.floor(maxBtns / 2));
        let endP = Math.min(totalPages, startP + maxBtns);
        if (endP - startP < maxBtns) startP = Math.max(0, endP - maxBtns);
        for (let i = startP; i < endP; i++) {
            btns += `<button class="${i === page ? 'active' : ''}" data-go="${i}">${i + 1}</button>`;
        }
        btns += `<button ${page === totalPages - 1 ? 'disabled' : ''} data-go="${page + 1}">Next →</button>`;
        pag.innerHTML = btns;
        pag.querySelectorAll('button[data-go]').forEach(b => {
            b.addEventListener('click', () => {
                page = parseInt(b.dataset.go);
                renderReviews();
                document.getElementById('reviews').scrollIntoView({ behavior: 'smooth', block: 'start' });
            });
        });
    };

    // Search clear
    document.getElementById('searchClear').addEventListener('click', () => {
        const inp = document.getElementById('rvSearch');
        inp.value = ''; inp.focus(); applyFilters();
    });

    // Wire up filters (debounced search)
    document.getElementById('rvSearch').addEventListener('input', debounce(applyFilters, 200));
    document.getElementById('rvRating').addEventListener('change', applyFilters);
    document.getElementById('rvStatus').addEventListener('change', applyFilters);
    document.getElementById('rvSort').addEventListener('change', applyFilters);

    // Keyboard shortcuts
    document.addEventListener('keydown', (e) => {
        if (e.key === '/' && document.activeElement.tagName !== 'INPUT') {
            e.preventDefault();
            document.getElementById('rvSearch').focus();
        }
        if (e.key === 'Escape' && document.activeElement.id === 'rvSearch') {
            document.getElementById('rvSearch').value = '';
            applyFilters();
            document.activeElement.blur();
        }
    });

    applyFilters();
});